t.script:
//                                                                                                                                                                
document.addEventListener('DOMContentLoaded', function () {
    function initForm() {
        // ---- Représentant légal ----
        var radiosLegal = document.querySelectorAll('input[name="legal_representation"]');
        if (radiosLegal.length === 0) {
            setTimeout(initForm, 100);
            return;
        }
        function updateLegalVisibility() {
    var checked = document.querySelector('input[name="legal_representation"]:checked');
    var val = checked ? checked.value : null;
    var p1 = document.getElementById('block_parent1');
    var p2 = document.getElementById('block_parent2');
    var other = document.getElementById('block_other');
    if (p1) p1.style.display = (val === 'both' || val === 'father_only') ? 'block' : 'none';
    if (p2) p2.style.display = (val === 'both' || val === 'mother_only') ? 'block' : 'none';
    if (other) other.style.display = (val === 'other') ? 'block' : 'none';
}
        radiosLegal.forEach(function(r) {
            r.addEventListener('change', updateLegalVisibility);
        });
        updateLegalVisibility();

        // ---- Même adresse parent 2 ----
        var cbSameAddr = document.getElementById('same_address_as_parent1');
        var blockAddr2 = document.getElementById('block_parent2_address');
        if (cbSameAddr && blockAddr2) {
            function toggleAddr2() {
                blockAddr2.style.display = cbSameAddr.checked ? 'none' : 'block';
            }
            cbSameAddr.addEventListener('change', toggleAddr2);
            toggleAddr2();
        }

        // ---- Gestion des élèves (ajout/suppression) ----
        var btnAdd = document.getElementById('btn_add_student');
        if (btnAdd) {
            btnAdd.addEventListener('click', function() {
                var template = document.querySelector('#new_student_template .card');
                if (!template) return;
                var clone = template.cloneNode(true);
                clone.querySelector('.btn-remove-new-student').addEventListener('click', function() {
                    clone.remove();
                });
                document.getElementById('students_list').appendChild(clone);
            });
        }
        document.addEventListener('click', function(e) {
            var btn = e.target.closest('.btn-remove-student');
            if (!btn) return;
            var lineId = btn.getAttribute('data-line-id');
            var input = document.createElement('input');
            input.type = 'hidden';
            input.name = 'delete_student_line_' + lineId;
            input.value = '1';
            document.querySelector('form').appendChild(input);
            btn.closest('.student-line').remove();
        });

        // ---- Aide employeur (gestion dynamique Oui/Non) ----
        var employerRadios = document.querySelectorAll('input[name="employer_assistance"]');
        var blockEmployerYes = document.getElementById('block_employer_yes');
        function toggleEmployerYes() {
            if (!blockEmployerYes) return;
            var selected = document.querySelector('input[name="employer_assistance"]:checked');
            var isYes = (selected && selected.value === 'yes');
            blockEmployerYes.style.display = isYes ? 'block' : 'none';
        }
        if (employerRadios.length && blockEmployerYes) {
            employerRadios.forEach(function(radio) {
                radio.addEventListener('change', toggleEmployerYes);
            });
            toggleEmployerYes();
        }

        // ---- Envoyer facture à l'employeur (affichage bloc coordonnées) ----
        var chkInvoice = document.getElementById('send_invoice_to_employer');
        var blockEmployerId = document.getElementById('block_employer_id');
        if (chkInvoice && blockEmployerId) {
            function toggleEmployerBlock() {
                // Forcer l'affichage en supprimant tout style inline conflictuel
                if (chkInvoice.checked) {
                    blockEmployerId.style.display = 'block';
                    blockEmployerId.style.removeProperty('display');
                } else {
                    blockEmployerId.style.display = 'none';
                }
            }
            // Initialisation et écoute
            toggleEmployerBlock();
            chkInvoice.addEventListener('change', toggleEmployerBlock);
        }
    }

    // ---- Gestion des forfaits et cotisation ----
function updateForfaitMontant(selectEl, montantInput) {
    var selectedOption = selectEl.options[selectEl.selectedIndex];
    var montant = 0;
    if (selectedOption && selectedOption.value) {
        var text = selectedOption.text;
        var match = text.match(/(\d+(?:\.\d+)?)\s*CHF/);
        if (match) montant = parseFloat(match[1]);
    }
    montantInput.value = montant.toFixed(2);
    updateTotalMensuel();
    updateCotisation();
}

function updateTotalMensuel() {
    var total = 0;
    document.querySelectorAll('.montant-mensuel').forEach(function(input) {
        var val = parseFloat(input.value);
        if (!isNaN(val)) total += val;
    });
    document.getElementById('total_monthly_fee').innerText = total.toFixed(2);
}

function updateCotisation() {
    var legalChecked = document.querySelector('input[name="legal_representation"]:checked');
    var legalValue = legalChecked ? legalChecked.value : null;
    var hasParent2 = (legalValue === 'both' || legalValue === 'parent2');
    var hasOther = (legalValue === 'other');
    var montantCotisation = 0;
    if (hasOther) {
        montantCotisation = 0;
    } else if (hasParent2) {
        montantCotisation = 60;
    } else {
        montantCotisation = 40;
    }
    document.getElementById('membership_fee_amount').innerText = montantCotisation.toFixed(2);
}

document.querySelectorAll('.forfait-select').forEach(function(select) {
    var lineId = select.getAttribute('data-line-id');
    var montantInput = document.querySelector('.montant-mensuel[data-line-id="' + lineId + '"]');
    if (montantInput) {
        function onChange() { updateForfaitMontant(select, montantInput); }
        select.addEventListener('change', onChange);
        onChange();
    }
});

var legalRadios = document.querySelectorAll('input[name="legal_representation"]');
legalRadios.forEach(function(radio) {
    radio.addEventListener('change', updateCotisation);
});
updateCotisation();

    initForm();
});
//
